use strict;
use warnings;
use PDF::API2;
use Text::PDF::Text;

# Function to extract text from PDF
sub extract_text {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);
    my $text = '';
    for my $page (1 .. $pdf->pages) {
        my $page_obj = $pdf->open_page($page);
        $text .= $page_obj->text;
    }
    return $text;
}

# Function to extract date, author, and table information
sub extract_info {
    my ($text) = @_;
    my ($date, $author, $table_text) = (undef, undef, undef);

    # Extract date (assuming date is in the format: "Date: M/DD/YY")
    if ($text =~ /Date:\s*(\w+\s+\d+,\s+\d+)/) {
        $date = $1;
    }

    # Extract author (assuming author is in the format: "Author: John Doe")
    if ($text =~ /Author:\s*(\w+\s+\w+)/) {
        $author = $1;
    }

    # Extract table text (assuming table text is a block of text with one or more lines)
    $table_text = $text;
    $table_text =~ s/^\s*Date:\s*\w+\s+\d+,\s+\d+\s*.*\s*Author:\s*\w+\s+\w+\s*.*\s*//;

    return ($date, $author, $table_text);
}

