using ChromosomeType = double;

// Define the maximum and minimum values for the chromosome
const double CHROMOSOME_MAX = 100.0;
const double CHROMOSOME_MIN = 0.0;

// Function to evaluate the fitness of a chromosome
double fitnessFunction(ChromosomeType x) {
    return -pow(x, 2);  // We negate because we want to maximize x^2
}

// Function to generate a random chromosome
ChromosomeType generateRandomChromosome() {
    return CHROMOSOME_MIN + (CHROMOSOME_MAX - CHROMOSOME_MIN) * static_cast<double>(rand()) / RAND_MAX;
}

// Function to evaluate the fitness of a chromosome
int evaluateFitness(ChromosomeType chromosome) {
    return static_cast<int>(fitnessFunction(chromosome));
}

// Selection function: Random selection
ChromosomeType selectChromosome(const std::vector<ChromosomeType>& population) {
    int idx = rand() % population.size();
    return population[idx];
}

// Crossover function: Single-point crossover
ChromosomeType crossover(ChromosomeType parent1, ChromosomeType parent2) {
    double crossoverPoint = CHROMOSOME_MIN + (CHROMOSOME_MAX - CHROMOSOME_MIN) * static_cast<double>(rand()) / RAND_MAX;
    return (parent1 < crossoverPoint) ? parent1 : parent2;
}

